## 2. C / C++ glue (single compilation unit)

> **NOTE** – The code below is deliberately **stand‑alone**.  
> The mock `BlockIterator` and `Block` classes mimic the real BlockSci API but contain only the fields needed for the demo. Replace them with the real headers when you integrate.

```c
/* --------------------------------------------------------------
   blockscilua.c  –  Lua bindings for BlockSci (mocked version)
   -------------------------------------------------------------- */

#define LUA_COMPAT_MODULE
#include <lua.h>
#include <lauxlib.h>
#include <lualib.h>

#include <stdint.h>
#include <stdbool.h>
#include <stdio.h>
#include <string.h>
#include <time.h>

/* -----------------------------------------------------------------
   1.  Mock BlockSci C++ objects (replace with the real ones later)
   ----------------------------------------------------------------- */
#ifdef __cplusplus
extern "C" {
#endif

/* A tiny stand‑in for a Block object.  In the real library this would
   expose many more fields and methods. */
typedef struct {
    uint32_t height;
    uint8_t  hash[32];
    uint64_t timestamp;
    uint32_t tx_count;
    bool     has_op_return;
} MockBlock;

/* A simple forward‑only iterator over a contiguous range of blocks. */
typedef struct {
    uint32_t cur;      /* current height */
    uint32_t end;      /* exclusive end height */
} MockBlockIterator;

/* Create a new iterator that walks [start, end).  If end==0 we walk
   to the (mock) tip (here: 800'000'000). */
static MockBlockIterator* mock_it_new(uint32_t start, uint32_t end) {
    const uint32_t TIP = 800000000;
    if (end == 0) end = TIP;
    if (start > end) start = end;
    MockBlockIterator* it = (MockBlockIterator*)malloc(sizeof(MockBlockIterator));
    it->cur = start;
    it->end = end;
    return it;
}

/* Destroy the iterator. */
static void mock_it_del(MockBlockIterator* it) {
    free(it);
}

/* Return true if there is another block. */
static bool mock_it_has_next(const MockBlockIterator* it) {
    return it->cur < it->end;
}

/* Fill a MockBlock with deterministic data (for demo). */
static void mock_it_next(MockBlockIterator* it, MockBlock* out) {
    uint32_t h = it->cur++;
    out->height = h;
    /* deterministic pseudo‑hash: just repeat the height */
    memset(out->hash, (uint8_t)(h & 0xFF), sizeof(out->hash));
    out->timestamp = 1231006505ULL + (uint64_t)h * 600;  /* genesis + 10‑min blocks */
    out->tx_count = (h % 1000) + 1;
    out->has_op_return = (h % 7 == 0);   /* ~1/7 blocks have OP_RETURN */
}

/* -----------------------------------------------------------------
   2.  Lua userdata structures
   ----------------------------------------------------------------- */

/* The iterator userdata that lives in Lua. */
typedef struct {
    MockBlockIterator* it;   /* owned C++ iterator */
    int               cb_ref;/* Lua reference to the per‑block callback (LUA_REFNIL if none) */
    /* Re‑used Block userdata (see below). */
    struct BlockUserdata* block_ud;
} IteratorUserdata;

/* The Block userdata – a thin wrapper around MockBlock. */
typedef struct BlockUserdata {
    MockBlock block;          /* data for the *current* block */
} BlockUserdata;

/* -----------------------------------------------------------------
   3.  Helper macros & forward declarations
   ----------------------------------------------------------------- */
#define ITERATOR_MT   "BlockSci.Iterator"
#define BLOCK_MT      "BlockSci.Block"

static int iterator_gc(lua_State* L);
static int iterator_for_each(lua_State* L);
static int iterator_has_next(lua_State* L);
static int iterator_next(lua_State* L);

/* Block methods */
static int block_height(lua_State* L);
static int block_hash(lua_State* L);
static int block_timestamp(lua_State* L);
static int block_tx_count(lua_State* L);
static int block_has_op_return(lua_State* L);
static int block_tostring(lua_State* L);

/* One‑shot helper */
static int l_count_blocks(lua_State* L);

/* -----------------------------------------------------------------
   4.  Implementation
   ----------------------------------------------------------------- */

/* ---- Block userdata ------------------------------------------------ */
static BlockUserdata* push_block(lua_State* L) {
    BlockUserdata* b = (BlockUserdata*)lua_newuserdata(L, sizeof(BlockUserdata));
    luaL_getmetatable(L, BLOCK_MT);
    lua_setmetatable(L, -2);
    return b;
}

/* __tostring for debugging */
static int block_tostring(lua_State* L) {
    BlockUserdata* b = (BlockUserdata*)luaL_checkudata(L, 1, BLOCK_MT);
    char buf[64];
    snprintf(buf, sizeof(buf), "Block{height=%u}", b->block.height);
    lua_pushstring(L, buf);
    return 1;
}

/* height() → integer */
static int block_height(lua_State* L) {
    BlockUserdata* b = (BlockUserdata*)luaL_checkudata(L, 1, BLOCK_MT);
    lua_pushinteger(L, b->block.height);
    return 1;
}

/* hash() → hex string */
static int block_hash(lua_State* L) {
    BlockUserdata* b = (BlockUserdata*)luaL_checkudata(L, 1, BLOCK_MT);
    char hex[65];
    for (int i = 0; i < 32; ++i) {
        sprintf(hex + i*2, "%02x", b->block.hash[i]);
    }
    hex[64] = '\0';
    lua_pushstring(L, hex);
    return 1;
}

/* timestamp() → integer */
static int block_timestamp(lua_State* L) {
    BlockUserdata* b = (BlockUserdata*)luaL_checkudata(L, 1, BLOCK_MT);
    lua_pushinteger(L, (lua_Integer)b->block.timestamp);
    return 1;
}

/* tx_count() → integer */
static int block_tx_count(lua_State* L) {
    BlockUserdata* b = (BlockUserdata*)luaL_checkudata(L, 1, BLOCK_MT);
    lua_pushinteger(L, b->block.tx_count);
    return 1;
}

/* has_op_return() → boolean */
static int block_has_op_return(lua_State* L) {
    BlockUserdata* b = (BlockUserdata*)luaL_checkudata(L, 1, BLOCK_MT);
    lua_pushboolean(L, b->block.has_op_return);
    return 1;
}

/* ---- Iterator userdata ------------------------------------------- */
static IteratorUserdata* check_iterator(lua_State* L, int idx) {
    return (IteratorUserdata*)luaL_checkudata(L, idx, ITERATOR_MT);
}

/* __gc for iterator – destroys the C++ iterator and releases the
   callback reference (if any). */
static int iterator_gc(lua_State* L) {
    IteratorUserdata* iu = (IteratorUserdata*)luaL_checkudata(L, 1, ITERATOR_MT);
    if (iu->it) {
        mock_it_del(iu->it);
        iu->it = NULL;
    }
    if (iu->cb_ref != LUA_REFNIL) {
        luaL_unref(L, LUA_REGISTRYINDEX, iu->cb_ref);
        iu->cb_ref = LUA_REFNIL;
    }
    return 0;
}

/* has_next() → boolean – optional convenience method */
static int iterator_has_next(lua_State* L) {
    IteratorUserdata* iu = check_iterator(L, 1);
    lua_pushboolean(L, mock_it_has_next(iu->it));
    return 1;
}

/* next() → Block userdata (or nil if exhausted) */
static int iterator_next(lua_State* L) {
    IteratorUserdata* iu = check_iterator(L, 1);
    if (!mock_it_has_next(iu->it)) {
        lua_pushnil(L);
        return 1;
    }
    MockBlock blk;
    mock_it_next(iu->it, &blk);
    BlockUserdata* b = push_block(L);
    b->block = blk;               /* copy data into the userdata */
    return 1;
}

/* for_each(callback) – the hot loop */
static int iterator_for_each(lua_State* L) {
    IteratorUserdata* iu = check_iterator(L, 1);
    luaL_checktype(L, 2, LUA_TFUNCTION);
    /* Store the callback in the iterator (replace any previous one). */
    if (iu->cb_ref != LUA_REFNIL) luaL_unref(L, LUA_REGISTRYINDEX, iu->cb_ref);
    lua_pushvalue(L, 2);                /* copy callback to top */
    iu->cb_ref = luaL_ref(L, LUA_REGISTRYINDEX);

    /* Re‑use a single Block userdata for every iteration – this avoids
       allocation and GC pressure. */
    if (!iu->block_ud) {
        iu->block_ud = push_block(L);   /* pushes and leaves it on stack */
        lua_pop(L, 1);                  /* we keep the pointer, not the stack slot */
    }

    /* ----------------------------------------------------------------
       Hot loop:  while (has_next) { fetch block; call Lua callback; }
       ---------------------------------------------------------------- */
    while (mock_it_has_next(iu->it)) {
        MockBlock blk;
        mock_it_next(iu->it, &blk);
        iu->block_ud->block = blk;       /* update the reused userdata */

        /* Push callback */
        lua_rawgeti(L, LUA_REGISTRYINDEX, iu->cb_ref);        /* +1 */
        lua_pushvalue(L, -2);            /* the block userdata (already on stack) */
        /* Stack: ... cb block */

        /* Call the callback with 1 argument, 1 return value. */
        if (lua_pcall(L, 1, 1, 0) != LUA_OK) {
            /* Propagate the Lua error – the iterator is left in a
               partially‑consumed state; that's fine. */
            return lua_error(L);
        }
        /* Stack: ... retval */
        int cont = lua_toboolean(L, -1);    /* any truthy value = continue */
        lua_pop(L, 1);                      /* discard retval */

        if (!cont) break;                   /* early‑exit requested */
    }

    /* Cleanup: we keep the iterator alive for the user; the callback
       reference stays stored so the user can call for_each again. */
    return 0;   /* no values returned */
}

/* ---- Library entry points ------------------------------------------ */

/* blocks([start, end]) → iterator */
static int l_blocks(lua_State* L) {
    int nargs = lua_gettop(L);
    uint32_t start = 0, end = 0;   /* defaults: start=0, end=0 (walk to tip) */
    if (nargs >= 1) start = (uint32_t)luaL_checkinteger(L, 1);
    if (nargs >= 2) end   = (uint32_t)luaL_checkinteger(L, 2);

    IteratorUserdata* iu = (IteratorUserdata*)lua_newuserdata(L, sizeof(IteratorUserdata));
    iu->it = mock_it_new(start, end);
    iu->cb_ref = LUA_REFNIL;
    iu->block_ud = NULL;

    luaL_getmetatable(L, ITERATOR_MT);
    lua_setmetatable(L, -2);
    return 1;   /* returns the iterator userdata */
}

/* count_blocks(callback, [start, end]) → integer
   Implements the “apply‑and‑reduce” pattern that pandas/polars expose:
   run a predicate on each block and count the true results. */
static int l_count_blocks(lua_State* L) {
    luaL_checktype(L, 1, LUA_TFUNCTION);
    int nargs = lua_gettop(L);
    uint32_t start = 0, end = 0;
    if (nargs >= 2) start = (uint32_t)luaL_checkinteger(L, 2);
    if (nargs >= 3) end   = (uint32_t)luaL_checkinteger(L, 3);

    /* Build a temporary iterator (no need to expose it to Lua). */
    MockBlockIterator* it = mock_it_new(start, end);
    int64_t count = 0;

    /* Re‑use a Block userdata for the callback – same trick as above. */
    lua_pushvalue(L, 1);                     /* keep callback at index 1 */
    BlockUserdata* b = push_block(L);       /* push a fresh Block userdata */
    int cb_idx = 1;                          /* callback is at stack index 1 */

    while (mock_it_has_next(it)) {
        MockBlock blk;
        mock_it_next(it, &blk);
        b->block = blk;                      /* update userdata */

        lua_pushvalue(L, cb_idx);            /* callback */
        lua_pushvalue(L, -2);                /* block userdata */

        if (lua_pcall(L, 1, 1, 0) != LUA_OK) {
            /* Propagate error – clean up */
            mock_it_del(it);
            return lua_error(L);
        }
        int keep = lua_toboolean(L, -1);
        lua_pop(L, 1);                       /* discard result */
        if (keep) ++count;
    }

    mock_it_del(it);
    lua_pushinteger(L, count);
    return 1;
}

/* -----------------------------------------------------------------
   5.  Register metatables & library functions
   ----------------------------------------------------------------- */
static const luaL_Reg iterator_methods[] = {
    {"for_each", iterator_for_each},
    {"has_next", iterator_has_next},
    {"next",     iterator_next},
    {NULL, NULL}
};

static const luaL_Reg block_methods[] = {
    {"height",          block_height},
    {"hash",            block_hash},
    {"timestamp",       block_timestamp},
    {"tx_count",        block_tx_count},
    {"has_op_return",   block_has_op_return},
    {"__tostring",      block_tostring},
    {NULL, NULL}
};

static const luaL_Reg lib_funcs[] = {
    {"blocks",        l_blocks},
    {"count_blocks",  l_count_blocks},
    {NULL, NULL}
};

int luaopen_blockscilua(lua_State* L) {
    /* Create Block metatable */
    luaL_newmetatable(L, BLOCK_MT);               /* mt */
    lua_pushvalue(L, -1);                         /* mt mt */
    lua_setfield(L, -2, "__index");               /* mt.__index = mt */
    luaL_setfuncs(L, block_methods, 0);
    lua_pop(L, 1);                                /* drop mt */

    /* Create Iterator metatable */
    luaL_newmetatable(L, ITERATOR_MT);
    lua_pushvalue(L, -1);
    lua_setfield(L, -2, "__index");
    luaL_setfuncs(L, iterator_methods, 0);
    lua_pushcfunction(L, iterator_gc);
    lua_setfield(L, -2, "__gc");
    lua_pop(L, 1);

    /* Register library table */
    luaL_newlib(L, lib_funcs);
    return 1;
}
```

