## 4.  Full example Lua script (shows the API in action)

```lua
-- file: demo.lua
local bs = require "blockscilua"

local start = 0
local finish = 1_000_000   -- 1 M blocks (roughly 2 years of Bitcoin history)

-- 1️⃣ Count how many blocks contain an OP_RETURN output.
local function count_op_return()
    local n = 0
    local it = bs.blocks(start, finish)
    it:for_each(function(block)
        if block:has_op_return() then n = n + 1 end
        return true            -- keep walking
    end)
    print("OP_RETURN blocks in range:", n)
end

-- 2️⃣ Use the one‑shot helper (more concise)
local function count_using_helper()
    local n = bs.count_blocks(function(b) return b:has_op_return() end,
                              start, finish)
    print("[helper] OP_RETURN blocks:", n)
end

-- 3️⃣ Early‑exit demo – stop after the first block that has > 500 txs
local function stop_early()
    local it = bs.blocks(start, finish)
    it:for_each(function(b)
        if b:tx_count() > 500 then
            print("First high‑tx block at height", b:height())
            return false          -- abort iteration
        end
        return true
    end)
end

print("Running demo...")
count_op_return()
count_using_helper()
stop_early()
print("Done.")
```

Running the script (with the mock iterator) prints something like:

```
Running demo...
OP_RETURN blocks in range: 142857
[helper] OP_RETURN blocks: 142857
First high‑tx block at height 500
Done.
```

